INSERT INTO public.operational_clients (
  id,
  commercial_id,
  client_name,
  clinic_name,
  plan,
  deal_value,
  creative_source,
  team_id,
  assigned_gestor_id,
  assigned_atendente_id,
  assigned_design_id,
  assigned_editor_video_id,
  status_operacional,
  onboarding_stage,
  stage_marketing,
  stage_trafego,
  stage_atendimento,
  onboarding_start_at,
  onboarding_done_at,
  activated_at,
  client_tier,
  pacote,
  pagador_anuncio,
  ad_account_name,
  has_recharge,
  recharge_value,
  start_meeting_date,
  renewal_due_date,
  renewal_date,
  renewal_status,
  churn_date,
  churn_status,
  churn_reason,
  nps_sent,
  nps_answered,
  created_at,
  updated_at,
  status_updated_at
)
SELECT
  s.id,
  s.commercial_id,
  s.client_name,
  s.clinic_name,
  s.plan,
  s.deal_value,
  s.creative_source,
  s.team_id::uuid,
  s.assigned_gestor_id::uuid,
  s.assigned_atendente_id::uuid,
  s.assigned_design_id::uuid,
  s.assigned_editor_video_id::uuid,
  s.status_operacional,
  s.onboarding_stage,
  s.stage_marketing,
  s.stage_trafego,
  s.stage_atendimento,
  s.onboarding_start_at,
  s.onboarding_done_at,
  s.activated_at,
  s.client_tier,
  s.pacote,
  s.pagador_anuncio,
  s.ad_account_name,
  s.has_recharge,
  s.recharge_value,
  s.start_meeting_date,
  s.renewal_due_date,
  s.renewal_date,
  s.renewal_status,
  s.churn_date,
  s.churn_status,
  s.churn_reason,
  s.nps_sent,
  s.nps_answered,
  s.created_at,
  s.updated_at,
  s.status_updated_at
FROM source_rows s
WHERE NOT EXISTS (
  SELECT 1
  FROM public.operational_clients oc
  WHERE lower(trim(coalesce(oc.client_name, ''))) = lower(trim(s.client_name))
);

